import React, { useState, useEffect } from "react";
import ReactDOM from 'react-dom';
import ctl from "@netlify/classnames-template-literals";
import { Tab, Tabs, TabList, TabPanel } from 'react-tabs';
import ReactHtmlParser from 'react-html-parser'; 
import axios from 'axios';

let productData = null;

const tabClasses = ctl(`
text-gray-600
py-2
px-6
my-5
block 
hover:text-indigo-500 
focus:outline-none 
text-indigo-900
border-b-2 
font-bold
border-blue-900
`)



function Product(props){
    const [product, setProduct] = useState(null)

    useEffect(() => {
        console.log(productData)
        if(Object.is(productData, null)){
            axios.get(`https://api-test.innoloft.com/product/6781/`).then(res => {

                productData = res.data;
                setProduct(productData)
            }).catch(err => console.log(err))
        }
    })

    function handleChange(e){
        if(e.target.dataset.tag === 'categories'){
            const categories = [...product.categories]
            categories[e.target.dataset.index] = {
                id: e.target.id,
                name: e.target.value
            }
            setProduct({...product, categories: categories})
        } else {
            const businessModel = [...product.businessModel]
            businessModel[e.target.dataset.index] = {
                id: e.target.id,
                name: e.target.value
            }
            setProduct({...product, businessModel: businessModel})
        }

    }

    function replaceElement(e){
        e.preventDefault()
        const textArea = <textarea data-tag={e.target.dataset.tag} id={e.target.id} value={product[e.target.dataset.tag][e.target.dataset.index].name} onBlur={()=>{}} onChange={handleChange}></textarea>
        ReactDOM.unmountComponentAtNode(e.target)
        ReactDOM.render(textArea, e.target.parentElement)
    }

    function replaceTextArea(){
        const activeTextArea = document.getElementsByTagName('textarea')[0]
        if(activeTextArea){
            const content = activeTextArea.textContent;
            const textElement = <p id={activeTextArea.id}>{content}</p>
            ReactDOM.render(textElement, activeTextArea)
        }
    }

    return ( 
        <div className="max-w-screen-2xl mx-auto flex" onClick={replaceTextArea}>
            <div className="w-1/2 mx-10">
                <div className="w-4/5 flex mt-10 p-4 rounded-md border-l-8 border-solid border-indigo-900">
                    <img src={product?.picture} alt="product" className="w-36 rounded-full justify-center"/>
                    <div className="flex-col ml-20 self-center">
                        <h2 className="font-bold text-4xl text-indigo-900">{product?.name}</h2>
                        <p className="font-semibold text-2xl text-indigo-600">{product?.type.name}</p>
                    </div>
                </div>
                {/* image

                description tab - attributes tab (editable)
                tab content */}
                <Tabs >
                    <TabList className="flex font-bold text-3xl">
                        <Tab className={tabClasses}>Description</Tab>
                        <Tab className={tabClasses}>Attributes</Tab>
                    </TabList>

                    <TabPanel>
                        <div>{ReactHtmlParser(product?.description)}</div>
                    </TabPanel>
                    <TabPanel>
                        <div className="flex justify-evenly">
                            <div>
                            <h2 className="font-semibold text-2xl text-indigo-600">Categories:</h2>
                            {product?.categories.map((category,i) => {

                                return(<div className="border-l-8 border-solid border-indigo-900 mt-5 pl-5 w-full">
                                    <p data-index={i} data-tag="categories" onClick={replaceElement} id={category.id}>{category.name}</p>
                                </div>) 

                            })}
                            </div>
                            <div>
                            <h2 className="font-semibold text-2xl text-indigo-600">Business models:</h2>
                            {product?.businessModels.map((businessModel,i) => {

                                return(<div className="border-l-8 border-solid border-indigo-900 mt-5 pl-5 w-full">
                                    <p data-index={i} data-tag="businessModels" id={businessModel.id}>{businessModel.name}</p>
                                </div>) 
                            })} 
                            </div>
                        </div>
                    </TabPanel>
                </Tabs>
            </div>
            <div className="lg:w-2/5">
                <div className="flex justify-between mt-10 p-4 rounded-full border-8 border-solid border-indigo-900">
                    <img src={product?.user.profilePicture} alt="user profile picture" className="w-32 rounded-full justify-center"/>
                    <div className="flex-col self-center ml-5">
                    <p className="font-bold text-4xl text-indigo-900">{product?.user.firstName + ' ' + product?.user.lastName}</p>
                    <p className="font-semibold text-2xl text-indigo-600">{product?.company.name}</p>
                    </div>
                </div>
                <div>
                    <h2 className="font-bold text-2xl text-indigo-900 mt-10 mb-5">Company Location: </h2>
                    <iframe
                        src={`https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3966.521260322283!2d106.8195613507864!3d-6.194741395493371!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69f5390917b759%3A0x6b45e67356080477!2sPT%20Kulkul%20Teknologi%20Internasional!5e0!3m2!1sen!2sid!4v1601138221085!5m2!1sen!2sid`}
                        className="w-full h-96 rounded-md shadow-lg"
                        frameBorder="0"
                        style={{ border: 0 }}
                        allowFullScreen=""
                        aria-hidden="false"
                        tabIndex="0"
                    />
                </div>
            </div>  
        </div>
    )
}

export default Product;
